     1→# grammY stream
     2→
     3→Stream long text messages to Telegram.
     4→Make LLM output appear as animated message drafts before sending the message.
     5→
     6→## Quickstart
     7→
     8→Here is a quickstart for you, but be sure to check out [the real documentation on the website](https://grammy.dev/plugins/stream).
     9→
    10→Run `npm i grammy @grammyjs/stream @grammyjs/auto-retry` and paste the following code:
    11→
    12→```ts
    13→import { Bot, type Context } from "grammy";
    14→import { autoRetry } from "@grammyjs/auto-retry";
    15→import { stream, type StreamFlavor } from "@grammyjs/stream";
    16→
    17→type MyContext = StreamFlavor<Context>;
    18→
    19→const bot = new Bot<MyContext>("");
    20→
    21→bot.api.config.use(autoRetry());
    22→bot.use(stream());
    23→
    24→async function* slowText() {
    25→    // emulate slow text generation
    26→    yield "This i";
    27→    await new Promise((r) => setTimeout(r, 1000));
    28→    yield "s some sl";
    29→    await new Promise((r) => setTimeout(r, 1000));
    30→    yield "owly gene";
    31→    await new Promise((r) => setTimeout(r, 1000));
    32→    yield "rated text";
    33→}
    34→
    35→bot.command("stream", async (ctx) => {
    36→    await ctx.replyWithStream(slowText());
    37→});
